// =========================
// NEXA SAFETY - FINAL SERVER
// =========================

const express = require("express");
const sqlite3 = require("sqlite3").verbose();
const cors = require("cors");
const jwt = require("jsonwebtoken");
const bcrypt = require("bcryptjs");
const path = require("path");

const app = express();

// =========================
// CONFIG
// =========================
const PORT = process.env.PORT || 3000;
const SECRET_KEY = "NEXA_SAFETY_SECRET";

// =========================
// MIDDLEWARE
// =========================
app.use(cors());
app.use(express.json());

// ✅ SERVE FRONTEND (IMPORTANT)
app.use(express.static(path.join(__dirname, "frontend")));

// =========================
// DATABASE
// =========================
const db = new sqlite3.Database("./nexa.db");

// USERS TABLE
db.run(`
CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    email TEXT UNIQUE,
    password TEXT
)
`);

// INCIDENTS TABLE
db.run(`
CREATE TABLE IF NOT EXISTS incidents (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    date TEXT,
    location TEXT,
    department TEXT,
    severity TEXT,
    description TEXT
)
`);

// =========================
// AUTH MIDDLEWARE
// =========================
function auth(req, res, next) {
    const header = req.headers.authorization;

    if (!header) return res.status(401).json({ error: "No token" });

    const token = header.split(" ")[1];

    jwt.verify(token, SECRET_KEY, (err, user) => {
        if (err) return res.status(403).json({ error: "Invalid token" });

        req.user = user;
        next();
    });
}

// =========================
// CREATE TEST USER
// =========================
app.get("/create-test-user", async (req, res) => {

    const password = await bcrypt.hash("1234", 10);

    db.run(
        `INSERT OR IGNORE INTO users (email, password)
         VALUES (?, ?)`,
        ["admin@nexa.com", password],
        function (err) {
            if (err) return res.json(err);

            res.json({ message: "Test user ready: admin@nexa.com / 1234" });
        }
    );
});

// =========================
// LOGIN
// =========================
app.post("/login", (req, res) => {

    const { email, password } = req.body;

    db.get("SELECT * FROM users WHERE email = ?", [email], async (err, user) => {

        if (!user) return res.json({ error: "User not found" });

        const valid = await bcrypt.compare(password, user.password);

        if (!valid) return res.json({ error: "Wrong password" });

        const token = jwt.sign({ id: user.id }, SECRET_KEY, { expiresIn: "8h" });

        res.json({ token });
    });
});

// =========================
// ADD INCIDENT
// =========================
app.post("/add-incident", auth, (req, res) => {

    const { date, location, department, severity, description } = req.body;

    db.run(
        `INSERT INTO incidents (date, location, department, severity, description)
         VALUES (?, ?, ?, ?, ?)`,
        [date, location, department, severity, description],
        function (err) {
            if (err) return res.status(500).json(err);

            res.json({ message: "Incident added", id: this.lastID });
        }
    );
});

// =========================
// GET INCIDENTS (POWER BI)
// =========================
app.get("/incidents", auth, (req, res) => {

    db.all("SELECT * FROM incidents", [], (err, rows) => {
        if (err) return res.status(500).json(err);

        res.json(rows);
    });
});

