// =========================
// RISK ANALYSIS ENGINE
// =========================
app.get("/risk-analysis", auth, (req, res) => {

    db.all("SELECT * FROM incidents", [], (err, rows) => {

        const result = rows.map(r => {

            let severityScore =
                r.severity === "High" ? 3 :
                r.severity === "Medium" ? 2 : 1;

            let likelihood = Math.random() * 3;

            let riskScore = severityScore * likelihood;

            let riskLevel = "Low";

            if (riskScore > 6) riskLevel = "High";
            else if (riskScore > 3) riskLevel = "Medium";

            return {
                ...r,
                severityScore,
                likelihood: likelihood.toFixed(2),
                riskScore: riskScore.toFixed(2),
                riskLevel
            };
        });

        res.json(result);
    });
});

// =========================
// AI PREDICTION ENGINE
// =========================
app.get("/predict-risk", auth, (req, res) => {

    db.all("SELECT * FROM incidents", [], (err, rows) => {

        const locationMap = {};

        rows.forEach(r => {

            let score =
                r.severity === "High" ? 3 :
                r.severity === "Medium" ? 2 : 1;

            locationMap[r.location] =
                (locationMap[r.location] || 0) + score;
        });

        const predictions = Object.keys(locationMap).map(loc => {

            const score = locationMap[loc];
            const probability = score / rows.length;

            let prediction = "LOW RISK";

            if (probability > 0.6) prediction = "CRITICAL FUTURE RISK";
            else if (probability > 0.3) prediction = "ELEVATED RISK";

            return {
                location: loc,
                score,
                probability: probability.toFixed(2),
                prediction
            };
        });

        res.json({
            model: "NEXA AI v1",
            predictions
        });
    });
});

// =========================
// HEATMAP
// =========================
app.get("/heatmap", auth, (req, res) => {

    db.all("SELECT * FROM incidents", [], (err, rows) => {

        const zones = {};

        rows.forEach(r => {

            let score =
                r.severity === "High" ? 3 :
                r.severity === "Medium" ? 2 : 1;

            zones[r.location] = (zones[r.location] || 0) + score;
        });

        const heatmap = Object.keys(zones).map(zone => {

            const score = zones[zone];

            let level = "LOW";
            let color = "green";

            if (score > 8) {
                level = "HIGH";
                color = "red";
            } else if (score > 4) {
                level = "MEDIUM";
                color = "orange";
            }

            return { zone, score, level, color };
        });

        res.json({ heatmap });
    });
});

// =========================
// DASHBOARD
// =========================
app.get("/dashboard", auth, (req, res) => {

    db.all("SELECT * FROM incidents", [], (err, rows) => {

        let high = 0, medium = 0, low = 0;

        rows.forEach(r => {
            if (r.severity === "High") high++;
            else if (r.severity === "Medium") medium++;
            else low++;
        });

        res.json({
            total: rows.length,
            high,
            medium,
            low
        });
    });
});

// =========================
// ROOT TEST
// =========================
app.get("/", (req, res) => {
    res.send("🚀 NEXA SAFETY API RUNNING");
});

// =========================
// START SERVER
// =========================
app.listen(PORT, () => {
    console.log(`🚀 Server running on http://localhost:${PORT}`);
});